  ('social-worker-moex-00745', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國家庭暴力防治法中關於保護令之聲請，下列敘述何者錯誤？', '["保護令之聲請，由被害人之住居所地、相對人之住居所地或家庭暴力發生地之地方法院管轄", "法院為定管轄權，得調查被害人之住居所", "保護令事件之審理以公開為原則，被害人得於審理時，聲請其個案輔導之社工人員陪同被害人 在場", "法院於審理終結前，得聽取直轄市、縣（市）主管機關或社會福利機構之意見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "2833fa197db9", "answer_pdf_sha1": "b2b06e4bb504", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00746', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '為維護未成年子女與家庭暴力加害人會面交往之權益，依家庭暴力防治法之相關規定，下列敘述 何者錯誤？', '["直轄市、縣（市）主管機關應設未成年子女會面交往處所或委託其他機關（構）、團體辦理，且 負擔監督會面交往之相關費用", "家庭暴力加害人會面交往其未成年子女時，須於特定安全場所，由第三人或機關、團體監督會 面交往", "家庭暴力加害人需繳納保證金，若未準時、安全交還子女，得沒入保證金", "法院如認加害人有違背命令之情形，或准許會面交往無法確保被害人或其子女之安全者，得依 聲請或依職權禁止之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "2833fa197db9", "answer_pdf_sha1": "b2b06e4bb504", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
